import numpy as np

def repeat_kv(kv_heads, n_rep):
    return np.repeat(kv_heads, n_rep, axis=2)

def run_practice():
    kv = np.array([[[[1.0], [2.0]]]]) # shape (1,1,2,1)
    rep = repeat_kv(kv, 2)
    assert rep.shape == (1, 1, 4, 1)
    print('[PASS] GQA KV repeat dimension matches.')

if __name__ == '__main__':
    run_practice()
